INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelle est la devise de la République française ?', 'qcm', '["Liberté, Égalité, Fraternité","Liberté, Justice, Solidarité","Égalité, Travail, Patrie","Unité, République, Démocratie"]'::jsonb, 'Liberté, Égalité, Fraternité', 'La devise de la République française est « Liberté, Égalité, Fraternité ». Elle figure dans l''article 2 de la Constitution de 1958.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est l''hymne national de la France ?', 'qcm', '["La Marseillaise","Le Chant du départ","La Parisienne","L''Internationale"]'::jsonb, 'La Marseillaise', 'La Marseillaise est l''hymne national français depuis 1879. Elle a été composée par Rouget de Lisle en 1792.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelles sont les couleurs du drapeau français, de gauche à droite ?', 'qcm', '["Bleu, blanc, rouge","Rouge, blanc, bleu","Bleu, rouge, blanc","Blanc, bleu, rouge"]'::jsonb, 'Bleu, blanc, rouge', 'Le drapeau tricolore est bleu, blanc, rouge. Il est le drapeau national depuis 1794 et figure dans l''article 2 de la Constitution.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qui est le chef de l''État en France ?', 'qcm', '["Le Président de la République","Le Premier ministre","Le Président du Sénat","Le Président de l''Assemblée nationale"]'::jsonb, 'Le Président de la République', 'Le Président de la République est le chef de l''État. Il est élu au suffrage universel direct pour 5 ans (article 6 de la Constitution).', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Pour combien d''années le Président de la République est-il élu ?', 'qcm', '["5 ans","4 ans","6 ans","7 ans"]'::jsonb, '5 ans', 'Depuis le référendum de 2000 (appliqué en 2002), le mandat présidentiel est de 5 ans (quinquennat), contre 7 ans auparavant.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527455', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qui nomme le Premier ministre ?', 'qcm', '["Le Président de la République","L''Assemblée nationale","Le Sénat","Le Conseil constitutionnel"]'::jsonb, 'Le Président de la République', 'Le Président de la République nomme le Premier ministre (article 8 de la Constitution). Il met fin à ses fonctions sur présentation de la démission du gouvernement.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527460', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Combien de chambres composent le Parlement français ?', 'qcm', '["2 (Assemblée nationale et Sénat)","1 (Assemblée nationale)","3 (Assemblée, Sénat et Conseil d''État)","2 (Sénat et Conseil constitutionnel)"]'::jsonb, '2 (Assemblée nationale et Sénat)', 'Le Parlement est bicaméral : il comprend l''Assemblée nationale (577 députés) et le Sénat (348 sénateurs). Article 24 de la Constitution.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241018', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel âge minimum faut-il avoir pour voter en France ?', 'qcm', '["18 ans","16 ans","21 ans","20 ans"]'::jsonb, '18 ans', 'Le droit de vote est accordé à tout citoyen français âgé d''au moins 18 ans, jouissant de ses droits civils et politiques.', 'https://www.service-public.fr/particuliers/vosdroits/F1939', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La France est une République :', 'qcm', '["Indivisible, laïque, démocratique et sociale","Fédérale, laïque et démocratique","Monarchique et constitutionnelle","Indivisible et religieuse"]'::jsonb, 'Indivisible, laïque, démocratique et sociale', 'L''article 1er de la Constitution dispose : « La France est une République indivisible, laïque, démocratique et sociale. »', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019240997', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Que signifie la laïcité en France ?', 'qcm', '["La séparation des Églises et de l''État","L''interdiction de toute religion","L''obligation d''être athée","La religion d''État est le catholicisme"]'::jsonb, 'La séparation des Églises et de l''État', 'La laïcité, inscrite dans la loi de 1905, garantit la liberté de conscience et la séparation des Églises et de l''État. Chacun est libre de croire ou de ne pas croire.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En quelle année la Déclaration des droits de l''homme et du citoyen a-t-elle été adoptée ?', 'qcm', '["1789","1791","1804","1848"]'::jsonb, '1789', 'La Déclaration des droits de l''homme et du citoyen a été adoptée le 26 août 1789. Elle fait partie du bloc de constitutionnalité.', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/declaration-des-droits-de-l-homme-et-du-citoyen-de-1789', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le principe qui garantit que tous les citoyens sont égaux devant la loi ?', 'qcm', '["L''égalité","La fraternité","La laïcité","La souveraineté"]'::jsonb, 'L''égalité', 'Le principe d''égalité devant la loi est inscrit dans l''article 1er de la DDHC : « Les hommes naissent et demeurent libres et égaux en droits. »', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/declaration-des-droits-de-l-homme-et-du-citoyen-de-1789', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'L''école publique en France est :', 'qcm', '["Gratuite, laïque et obligatoire (de 3 à 16 ans)","Gratuite et religieuse","Payante et obligatoire","Facultative jusqu''à 18 ans"]'::jsonb, 'Gratuite, laïque et obligatoire (de 3 à 16 ans)', 'L''instruction est obligatoire de 3 à 16 ans. L''école publique est gratuite et laïque (lois Ferry de 1881-1882, abaissement à 3 ans en 2019).', 'https://www.service-public.fr/particuliers/vosdroits/F1898', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelle est la fête nationale française ?', 'qcm', '["Le 14 juillet","Le 11 novembre","Le 8 mai","Le 1er mai"]'::jsonb, 'Le 14 juillet', 'Le 14 juillet est la fête nationale. Elle commémore la prise de la Bastille (1789) et la Fête de la Fédération (1790).', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel symbole représente la République française sous forme de femme ?', 'qcm', '["Marianne","Jeanne d''Arc","La Liberté","La Justice"]'::jsonb, 'Marianne', 'Marianne est la figure allégorique de la République française. Son buste est présent dans toutes les mairies.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qui vote les lois en France ?', 'qcm', '["Le Parlement (Assemblée nationale et Sénat)","Le Président de la République","Le Premier ministre","Le Conseil constitutionnel"]'::jsonb, 'Le Parlement (Assemblée nationale et Sénat)', 'Le Parlement vote les lois (article 34 de la Constitution). L''initiative législative appartient au Premier ministre et aux parlementaires.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241030', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La Constitution de la Ve République date de :', 'qcm', '["1958","1946","1789","1968"]'::jsonb, '1958', 'La Constitution de la Ve République a été adoptée par référendum le 28 septembre 1958 et promulguée le 4 octobre 1958.', 'https://www.legifrance.gouv.fr/loda/id/JORFTEXT000000571356', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Combien de régions compte la France métropolitaine ?', 'qcm', '["13","18","22","26"]'::jsonb, '13', 'Depuis la réforme de 2016, la France métropolitaine compte 13 régions. Avec les territoires d''outre-mer, on arrive à 18 régions au total.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le suffrage universel signifie que :', 'qcm', '["Tous les citoyens majeurs ont le droit de voter","Seuls les hommes votent","Seuls les propriétaires votent","Le vote est obligatoire"]'::jsonb, 'Tous les citoyens majeurs ont le droit de voter', 'Le suffrage universel permet à tout citoyen majeur de voter, sans condition de fortune, de sexe ou d''instruction. Les femmes votent depuis 1944.', 'https://www.service-public.fr/particuliers/vosdroits/F1939', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En quelle année les femmes ont-elles obtenu le droit de vote en France ?', 'qcm', '["1944","1936","1958","1968"]'::jsonb, '1944', 'L''ordonnance du 21 avril 1944 a accordé le droit de vote et d''éligibilité aux femmes. Elles ont voté pour la première fois le 29 avril 1945.', 'https://www.service-public.fr/particuliers/vosdroits/F1939', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le rôle du Conseil constitutionnel ?', 'qcm', '["Vérifier que les lois sont conformes à la Constitution","Voter les lois","Nommer le Premier ministre","Diriger l''armée"]'::jsonb, 'Vérifier que les lois sont conformes à la Constitution', 'Le Conseil constitutionnel contrôle la constitutionnalité des lois. Il comprend 9 membres nommés pour 9 ans.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527489', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Que garantit l''article 1er de la Déclaration des droits de l''homme ?', 'qcm', '["Les hommes naissent libres et égaux en droits","Le droit au travail","La liberté de la presse","Le droit de propriété"]'::jsonb, 'Les hommes naissent libres et égaux en droits', '« Les hommes naissent et demeurent libres et égaux en droits. Les distinctions sociales ne peuvent être fondées que sur l''utilité commune. » (Article 1er, DDHC 1789)', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/declaration-des-droits-de-l-homme-et-du-citoyen-de-1789', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Depuis quelle année l''abolition de la peine de mort est-elle effective en France ?', 'qcm', '["1981","1968","1945","2001"]'::jsonb, '1981', 'La peine de mort a été abolie par la loi du 9 octobre 1981, portée par Robert Badinter, garde des Sceaux.', 'https://www.legifrance.gouv.fr/loda/id/JORFTEXT000000517964', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Combien de députés siègent à l''Assemblée nationale ?', 'qcm', '["577","348","500","650"]'::jsonb, '577', 'L''Assemblée nationale comprend 577 députés, élus au suffrage universel direct pour 5 ans.', 'https://www.assemblee-nationale.fr/', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel texte fondamental commence par « Nous, peuple français » ?', 'qcm', '["Le préambule de la Constitution de 1946","La Déclaration des droits de l''homme","La Constitution de 1958","La Charte de l''environnement"]'::jsonb, 'Le préambule de la Constitution de 1946', 'Le préambule de la Constitution de 1946 proclame les droits sociaux (droit au travail, à la santé, à l''éducation). Il fait partie du bloc de constitutionnalité.', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/preambule-de-la-constitution-du-27-octobre-1946', '2026-01-01', 3);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le maire est élu pour une durée de :', 'qcm', '["6 ans","4 ans","5 ans","3 ans"]'::jsonb, '6 ans', 'Le maire est élu par le conseil municipal pour 6 ans, la durée du mandat municipal.', 'https://www.service-public.fr/particuliers/vosdroits/F1939', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La sécurité sociale en France a été créée en :', 'qcm', '["1945","1936","1958","1968"]'::jsonb, '1945', 'La Sécurité sociale a été créée par les ordonnances des 4 et 19 octobre 1945. Elle couvre les risques maladie, vieillesse, famille et accidents du travail.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel impôt finance principalement les services publics locaux (écoles, routes, etc.) ?', 'qcm', '["Les impôts locaux (taxe foncière, etc.)","La TVA","L''impôt sur les sociétés","L''ISF"]'::jsonb, 'Les impôts locaux (taxe foncière, etc.)', 'Les impôts locaux (taxe foncière, cotisation foncière des entreprises) financent les collectivités territoriales et leurs services publics.', 'https://www.service-public.fr/particuliers/vosdroits/N247', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le service national universel (SNU) s''adresse aux jeunes de :', 'qcm', '["15 à 17 ans","18 à 25 ans","16 à 21 ans","14 à 16 ans"]'::jsonb, '15 à 17 ans', 'Le SNU s''adresse aux jeunes de 15 à 17 ans et comporte un séjour de cohésion et une mission d''intérêt général.', 'https://www.service-public.fr/particuliers/vosdroits/F35804', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La liberté d''expression en France est-elle absolue ?', 'qcm', '["Non, elle est limitée par la loi (diffamation, incitation à la haine, etc.)","Oui, on peut tout dire sans limite","Non, elle n''existe pas en France","Oui, sauf pour les fonctionnaires"]'::jsonb, 'Non, elle est limitée par la loi (diffamation, incitation à la haine, etc.)', 'La liberté d''expression est un droit fondamental mais elle connaît des limites : diffamation, injure, incitation à la haine, apologie du terrorisme, etc.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qu''est-ce que la présomption d''innocence ?', 'qcm', '["Toute personne est considérée innocente jusqu''à preuve du contraire","La police ne peut pas arrêter un suspect","Un avocat est toujours gratuit","On ne peut pas être jugé deux fois"]'::jsonb, 'Toute personne est considérée innocente jusqu''à preuve du contraire', 'La présomption d''innocence signifie qu''une personne est considérée innocente tant qu''elle n''a pas été déclarée coupable par un tribunal. Article 9 de la DDHC.', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/declaration-des-droits-de-l-homme-et-du-citoyen-de-1789', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'L''Union européenne compte actuellement combien d''États membres ?', 'qcm', '["27","28","25","30"]'::jsonb, '27', 'Depuis le Brexit (2020), l''Union européenne compte 27 États membres. La France est un membre fondateur (traité de Rome, 1957).', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le mariage civil en France est célébré par :', 'qcm', '["Le maire ou un officier d''état civil","Un prêtre","Un notaire","Un juge"]'::jsonb, 'Le maire ou un officier d''état civil', 'En France, seul le mariage civil célébré à la mairie a une valeur juridique. Le mariage religieux n''a aucune valeur légale s''il n''est pas précédé du mariage civil.', 'https://www.service-public.fr/particuliers/vosdroits/F930', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'L''égalité entre les femmes et les hommes est garantie par :', 'qcm', '["La Constitution","Un simple décret","Une convention collective","Aucun texte officiel"]'::jsonb, 'La Constitution', 'L''article 1er de la Constitution de 1958 dispose que « la loi favorise l''égal accès des femmes et des hommes aux mandats électoraux et fonctions électives ».', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019240997', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelles sont les trois collectivités territoriales en France ?', 'qcm', '["Commune, département, région","Ville, canton, province","Arrondissement, département, État","Mairie, préfecture, ministère"]'::jsonb, 'Commune, département, région', 'Les collectivités territoriales de droit commun sont les communes, les départements et les régions (article 72 de la Constitution).', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241104', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'L''impôt sur le revenu sert principalement à :', 'qcm', '["Financer les services publics (santé, éducation, sécurité, etc.)","Payer les salaires des entreprises privées","Rembourser la dette personnelle des citoyens","Financer les partis politiques"]'::jsonb, 'Financer les services publics (santé, éducation, sécurité, etc.)', 'L''impôt finance les services publics : éducation, santé, sécurité, justice, infrastructures. C''est un devoir civique inscrit dans l''article 13 de la DDHC.', 'https://www.service-public.fr/particuliers/vosdroits/N247', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le numéro d''urgence européen (fonctionne dans toute l''UE) ?', 'qcm', '["112","15","17","114"]'::jsonb, '112', 'Le 112 est le numéro d''urgence européen. En France, le 15 est le SAMU, le 17 la police, le 18 les pompiers.', 'https://www.service-public.fr/particuliers/vosdroits/F32124', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le Défenseur des droits a pour mission de :', 'qcm', '["Défendre les droits des citoyens face à l''administration","Voter les lois","Commander l''armée","Juger les criminels"]'::jsonb, 'Défendre les droits des citoyens face à l''administration', 'Le Défenseur des droits est une autorité indépendante (article 71-1 de la Constitution) qui lutte contre les discriminations et défend les droits des usagers des services publics.', 'https://www.defenseurdesdroits.fr/', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La polygamie est-elle autorisée en France ?', 'vrai_faux', '["Non","Oui"]'::jsonb, 'Non', 'La polygamie est interdite en France. Le Code pénal punit la bigamie (article 433-20) d''un an d''emprisonnement et 45 000 € d''amende.', 'https://www.legifrance.gouv.fr/codes/article_lc/LEGIARTI000006418660', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En France, l''éducation est un droit et un devoir pour :', 'qcm', '["Tous les enfants résidant en France, quelle que soit leur nationalité","Uniquement les enfants français","Uniquement les enfants dont les parents travaillent","Les enfants de plus de 6 ans"]'::jsonb, 'Tous les enfants résidant en France, quelle que soit leur nationalité', 'Tout enfant résidant en France a droit à l''instruction, quelle que soit sa nationalité ou celle de ses parents (article L131-1 du Code de l''éducation).', 'https://www.service-public.fr/particuliers/vosdroits/F1898', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le droit de grève en France est :', 'qcm', '["Un droit constitutionnel","Interdit","Réservé aux fonctionnaires","Soumis à autorisation du préfet"]'::jsonb, 'Un droit constitutionnel', 'Le droit de grève est reconnu par le préambule de la Constitution de 1946 (alinéa 7) : « Le droit de grève s''exerce dans le cadre des lois qui le réglementent. »', 'https://www.legifrance.gouv.fr/contenu/menu/droit-national-en-vigueur/constitution/preambule-de-la-constitution-du-27-octobre-1946', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel document doit-on présenter pour voter ?', 'qcm', '["Une pièce d''identité (dans les communes de plus de 1 000 habitants)","Un passeport uniquement","La carte d''électeur suffit toujours","Un justificatif de domicile"]'::jsonb, 'Une pièce d''identité (dans les communes de plus de 1 000 habitants)', 'Dans les communes de plus de 1 000 habitants, un titre d''identité est obligatoire pour voter. La carte électorale seule ne suffit pas.', 'https://www.service-public.fr/particuliers/vosdroits/F1939', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En France, la justice est rendue au nom de :', 'qcm', '["Le peuple français","Le Président de la République","Le Parlement","L''Union européenne"]'::jsonb, 'Le peuple français', 'La justice est rendue au nom du peuple français (article 454 du Code de procédure civile). Les jugements portent la mention « Au nom du peuple français ».', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527476', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Quel est le niveau de français requis pour obtenir la carte de résident 10 ans ?', 'qcm', '["B1 (oral et écrit)","A2","B2","C1"]'::jsonb, 'B1 (oral et écrit)', 'Depuis la loi du 26 janvier 2024, le niveau B1 à l''oral ET à l''écrit est requis pour la carte de résident de 10 ans.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Quel est le niveau de français requis pour la naturalisation depuis le 1er janvier 2026 ?', 'qcm', '["B2","B1","A2","C1"]'::jsonb, 'B2', 'Depuis le 1er janvier 2026, le niveau B2 est exigé pour toute demande de naturalisation (décret n° 2025-648 du 15 juillet 2025).', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Quel est le niveau de français requis pour la carte de séjour pluriannuelle (2-4 ans) ?', 'qcm', '["A2","A1","B1","B2"]'::jsonb, 'A2', 'Le niveau A2 est requis pour le renouvellement et l''obtention de la carte de séjour pluriannuelle (2 à 4 ans).', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Quels tests de langue sont acceptés pour prouver son niveau de français ?', 'qcm', '["TCF IRN et TEF","Uniquement le DELF","Seulement le baccalauréat français","Aucun test n''est accepté"]'::jsonb, 'TCF IRN et TEF', 'Le TCF IRN (Test de Connaissance du Français pour l''Intégration, la Résidence et la Nationalité) et le TEF sont les tests reconnus. Le DELF/DALF et les diplômes français sont aussi acceptés.', 'https://www.france-education-international.fr/tcf-irn', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Quelle est la durée de validité d''une attestation de niveau de langue ?', 'qcm', '["2 ans","1 an","5 ans","Illimitée"]'::jsonb, '2 ans', 'L''attestation de niveau de langue (TCF, TEF) est valable 2 ans. Les diplômes (DELF, DALF) sont valables sans limite.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Un diplôme de l''enseignement supérieur français dispense-t-il du test de langue ?', 'vrai_faux', '["Oui","Non"]'::jsonb, 'Oui', 'Un diplôme français de niveau bac ou supérieur (licence, master, etc.) dispense du test de langue car il atteste d''un niveau suffisant.', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111101', 'Combien d''épreuves comporte le TCF IRN ?', 'qcm', '["4 (compréhension orale, compréhension écrite, expression orale, expression écrite)","2 (oral et écrit)","3 (écoute, lecture, écriture)","1 seule épreuve globale"]'::jsonb, '4 (compréhension orale, compréhension écrite, expression orale, expression écrite)', 'Le TCF IRN évalue 4 compétences : compréhension orale, compréhension écrite, expression orale et expression écrite.', 'https://www.france-education-international.fr/tcf-irn', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'Combien d''années de résidence régulière faut-il pour demander la carte de résident 10 ans ?', 'qcm', '["5 ans","3 ans","10 ans","7 ans"]'::jsonb, '5 ans', 'La carte de résident nécessite 5 ans de résidence régulière et ininterrompue en France avec un titre de séjour valide.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'Quel est le montant minimum de ressources pour la carte de résident ?', 'qcm', '["Le SMIC (salaire minimum)","2 fois le SMIC","Aucun minimum","Le RSA"]'::jsonb, 'Le SMIC (salaire minimum)', 'Le demandeur doit justifier de ressources stables, régulières et suffisantes, au moins égales au SMIC.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'La carte de résident 10 ans est-elle renouvelable ?', 'vrai_faux', '["Oui, de plein droit","Non"]'::jsonb, 'Oui, de plein droit', 'La carte de résident est renouvelable de plein droit (art. L.433-4 CESEDA) sauf menace pour l''ordre public ou fraude avérée.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'Par quelle plateforme en ligne dépose-t-on la demande de carte de résident ?', 'qcm', '["L''ANEF (Administration Numérique pour les Étrangers en France)","Ameli.fr","Pôle emploi","La CAF"]'::jsonb, 'L''ANEF (Administration Numérique pour les Étrangers en France)', 'Le dépôt se fait en ligne via l''ANEF, au plus tôt 4 mois et au plus tard 2 mois avant la fin de validité du titre.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'Faut-il un casier judiciaire vierge pour la carte de résident ?', 'vrai_faux', '["Oui","Non"]'::jsonb, 'Oui', 'L''absence de condamnation pénale incompatible est vérifiée. Un casier judiciaire chargé peut entraîner un refus.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'L''examen civique est-il obligatoire pour la première demande de carte de résident ?', 'vrai_faux', '["Oui","Non"]'::jsonb, 'Oui', 'Depuis la loi du 26 janvier 2024, la réussite à l''examen civique est obligatoire pour la première demande de carte de résident.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'À partir de quel âge est-on dispensé de l''examen civique et du niveau de langue pour la carte de résident ?', 'qcm', '["65 ans","60 ans","70 ans","Aucune dispense"]'::jsonb, '65 ans', 'Les personnes de plus de 65 ans sont dispensées de l''examen civique et du justificatif de niveau de langue pour la carte de résident.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111102', 'Quand au plus tôt peut-on déposer sa demande de renouvellement de titre de séjour sur l''ANEF ?', 'qcm', '["4 mois avant l''expiration","6 mois avant","1 mois avant","À tout moment"]'::jsonb, '4 mois avant l''expiration', 'Le dépôt sur l''ANEF est possible au plus tôt 4 mois et au plus tard 2 mois avant la fin de validité du titre en cours.', 'https://www.service-public.fr/particuliers/vosdroits/F11201', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Quelles sont les deux voies principales pour obtenir la nationalité française ?', 'qcm', '["Par décret (naturalisation) et par déclaration (mariage)","Par naissance uniquement","Par achat","Par le service militaire"]'::jsonb, 'Par décret (naturalisation) et par déclaration (mariage)', 'La nationalité peut s''acquérir par naturalisation (décret) après 5 ans de résidence, ou par déclaration après 4 ans de mariage avec un(e) Français(e).', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Combien d''années de résidence faut-il pour demander la naturalisation par décret ?', 'qcm', '["5 ans","3 ans","10 ans","2 ans"]'::jsonb, '5 ans', 'La naturalisation par décret nécessite en principe 5 ans de résidence habituelle et régulière en France. Ce délai peut être réduit à 2 ans pour les études supérieures en France.', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Quel est le seuil de réussite à l''examen civique pour la naturalisation ?', 'qcm', '["32/40 (80%)","20/40 (50%)","36/40 (90%)","40/40 (100%)"]'::jsonb, '32/40 (80%)', 'L''examen civique comporte 40 questions en QCM. Le seuil de réussite est fixé à 32 bonnes réponses sur 40, soit 80%.', 'https://www.immigration.interieur.gouv.fr', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Auprès de qui dépose-t-on un dossier de naturalisation ?', 'qcm', '["La plateforme de naturalisation de son département","La mairie","Pôle emploi","L''ambassade du pays d''origine"]'::jsonb, 'La plateforme de naturalisation de son département', 'Le dossier est déposé auprès de la plateforme de naturalisation du département de résidence (ou du consulat pour les Français de l''étranger).', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Après combien d''années de mariage avec un(e) Français(e) peut-on demander la nationalité par déclaration ?', 'qcm', '["4 ans","2 ans","5 ans","1 an"]'::jsonb, '4 ans', 'La déclaration de nationalité par mariage est possible après 4 ans de mariage, à condition que la communauté de vie n''ait pas cessé et que le conjoint français ait conservé sa nationalité.', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'L''examen civique pour la naturalisation se déroule sur quel support ?', 'qcm', '["Support numérique (tablette/ordinateur)","Sur papier uniquement","À l''oral uniquement","Par courrier"]'::jsonb, 'Support numérique (tablette/ordinateur)', 'L''examen civique se déroule sur support numérique dans un centre agréé, sous forme de QCM de 40 questions.', 'https://www.immigration.interieur.gouv.fr', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Le formulaire CERFA pour la naturalisation porte le numéro :', 'qcm', '["12753","15186","11527","13972"]'::jsonb, '12753', 'Le formulaire CERFA n°12753*02 est le formulaire de demande d''acquisition de la nationalité française par naturalisation.', 'https://www.service-public.fr/particuliers/vosdroits/R16995', '2026-01-01', 3);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111103', 'Peut-on être naturalisé français si l''on a un casier judiciaire ?', 'qcm', '["Cela dépend de la gravité des condamnations","Non, jamais","Oui, toujours","Uniquement après 10 ans sans infraction"]'::jsonb, 'Cela dépend de la gravité des condamnations', 'Certaines condamnations pénales empêchent la naturalisation. Les condamnations mineures ne sont pas forcément un obstacle. L''administration examine au cas par cas.', 'https://www.service-public.fr/particuliers/vosdroits/F11926', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le nom du texte qui organise les pouvoirs publics en France ?', 'qcm', '["La Constitution","Le Code civil","Le Code pénal","Le Code du travail"]'::jsonb, 'La Constitution', 'La Constitution du 4 octobre 1958 est la loi fondamentale qui organise les pouvoirs publics et définit les droits fondamentaux en France.', 'https://www.legifrance.gouv.fr/loda/id/JORFTEXT000000571356', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel fleuve traverse Paris ?', 'qcm', '["La Seine","La Loire","Le Rhône","La Garonne"]'::jsonb, 'La Seine', 'La Seine est le fleuve qui traverse Paris du sud-est au nord-ouest. Elle mesure 776 km au total.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelle est la plus longue rivière de France ?', 'qcm', '["La Loire","La Seine","Le Rhône","La Garonne"]'::jsonb, 'La Loire', 'La Loire est le plus long fleuve de France avec environ 1 012 km. Elle prend sa source au Mont Gerbier-de-Jonc.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Combien de pays partagent une frontière terrestre avec la France métropolitaine ?', 'qcm', '["8","6","5","10"]'::jsonb, '8', 'La France métropolitaine partage une frontière avec 8 pays : Belgique, Luxembourg, Allemagne, Suisse, Italie, Monaco, Espagne et Andorre.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qui a dit « L''État, c''est moi » ?', 'qcm', '["Louis XIV","Napoléon Bonaparte","Charles de Gaulle","Louis XVI"]'::jsonb, 'Louis XIV', 'Cette phrase est attribuée à Louis XIV (le Roi-Soleil), symbole de la monarchie absolue en France. Son règne a duré 72 ans (1643-1715).', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelle révolution a mis fin à la monarchie absolue en France ?', 'qcm', '["La Révolution française de 1789","La Révolution de 1848","Mai 1968","La Commune de 1871"]'::jsonb, 'La Révolution française de 1789', 'La Révolution française de 1789 a mis fin à la monarchie absolue et instauré les principes de liberté, égalité et souveraineté du peuple.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qui a fondé la Ve République ?', 'qcm', '["Charles de Gaulle","François Mitterrand","Napoléon III","Georges Clemenceau"]'::jsonb, 'Charles de Gaulle', 'Le général de Gaulle est le fondateur de la Ve République (1958). Il en fut le premier président (1959-1969).', 'https://www.legifrance.gouv.fr/loda/id/JORFTEXT000000571356', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quand la France a-t-elle aboli l''esclavage définitivement ?', 'qcm', '["1848","1794","1865","1945"]'::jsonb, '1848', 'L''esclavage a été définitivement aboli en France par le décret du 27 avril 1848, sous l''impulsion de Victor Schœlcher.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Les violences conjugales sont-elles punies par la loi en France ?', 'vrai_faux', '["Oui, c''est un délit","Non"]'::jsonb, 'Oui, c''est un délit', 'Les violences conjugales sont un délit puni par la loi (Code pénal). Elles peuvent entraîner jusqu''à 5 ans d''emprisonnement et 75 000 € d''amende (aggravation par le lien conjugal).', 'https://www.service-public.fr/particuliers/vosdroits/F12544', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qu''est-ce que le PACS ?', 'qcm', '["Un contrat entre deux personnes majeures pour organiser leur vie commune","Un contrat de travail","Un titre de séjour","Un diplôme"]'::jsonb, 'Un contrat entre deux personnes majeures pour organiser leur vie commune', 'Le PACS (Pacte Civil de Solidarité) est un contrat conclu entre deux personnes majeures, de sexe différent ou de même sexe, pour organiser leur vie commune.', 'https://www.service-public.fr/particuliers/vosdroits/N144', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En France, le mariage entre personnes de même sexe est-il autorisé ?', 'vrai_faux', '["Oui, depuis 2013","Non"]'::jsonb, 'Oui, depuis 2013', 'Le mariage entre personnes de même sexe est légal en France depuis la loi du 17 mai 2013 (loi Taubira).', 'https://www.service-public.fr/particuliers/vosdroits/F930', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le travail des enfants de moins de 16 ans est-il autorisé en France ?', 'qcm', '["Non, sauf cas exceptionnels très encadrés","Oui, à partir de 14 ans","Oui, avec l''accord des parents","Non, jamais aucune exception"]'::jsonb, 'Non, sauf cas exceptionnels très encadrés', 'Le travail des enfants est interdit avant 16 ans. Des exceptions existent pour le spectacle, la mode ou l''apprentissage junior, très encadrées par la loi.', 'https://www.service-public.fr/particuliers/vosdroits/F1649', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En France, les discriminations sont punies par la loi. Sur quel(s) critère(s) ?', 'qcm', '["Origine, sexe, religion, orientation sexuelle, handicap, âge, etc. (25+ critères)","Uniquement l''origine ethnique","Uniquement le sexe","Aucun critère n''est protégé"]'::jsonb, 'Origine, sexe, religion, orientation sexuelle, handicap, âge, etc. (25+ critères)', 'La loi interdit les discriminations fondées sur plus de 25 critères (article 225-1 du Code pénal) : origine, sexe, âge, handicap, religion, orientation sexuelle, apparence physique, etc.', 'https://www.defenseurdesdroits.fr/', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'La France est membre fondateur de quelle organisation internationale créée en 1945 ?', 'qcm', '["L''ONU (Organisation des Nations Unies)","L''OTAN","L''Union européenne","L''OMC"]'::jsonb, 'L''ONU (Organisation des Nations Unies)', 'La France est l''un des 5 membres permanents du Conseil de sécurité de l''ONU, créée en 1945 après la Seconde Guerre mondiale.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le rôle du Sénat ?', 'qcm', '["Examiner et voter les lois, représenter les collectivités territoriales","Commander l''armée","Nommer les juges","Gérer la police"]'::jsonb, 'Examiner et voter les lois, représenter les collectivités territoriales', 'Le Sénat est la chambre haute du Parlement. Il examine et vote les lois et représente les collectivités territoriales (article 24 de la Constitution).', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241018', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quelle est la durée du mandat d''un député ?', 'qcm', '["5 ans","4 ans","6 ans","7 ans"]'::jsonb, '5 ans', 'Les députés sont élus pour 5 ans au suffrage universel direct (sauf dissolution de l''Assemblée nationale).', 'https://www.assemblee-nationale.fr/', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qu''est-ce que le référendum ?', 'qcm', '["Une consultation directe du peuple sur une question ou un texte de loi","Une élection du Président","Un vote au Parlement","Une décision du Conseil constitutionnel"]'::jsonb, 'Une consultation directe du peuple sur une question ou un texte de loi', 'Le référendum permet au peuple de se prononcer directement sur un projet de loi ou une révision constitutionnelle (articles 11 et 89 de la Constitution).', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241000', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Le Président de la République peut-il dissoudre l''Assemblée nationale ?', 'vrai_faux', '["Oui","Non"]'::jsonb, 'Oui', 'Le Président peut dissoudre l''Assemblée nationale (article 12 de la Constitution), ce qui provoque de nouvelles élections législatives.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527462', '2026-01-01', 2);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Qu''est-ce qu''une motion de censure ?', 'qcm', '["Un vote de l''Assemblée qui renverse le gouvernement","Une loi sur la censure","Une décision du Président","Un veto du Sénat"]'::jsonb, 'Un vote de l''Assemblée qui renverse le gouvernement', 'La motion de censure (article 49 alinéa 3) permet à l''Assemblée nationale de mettre en cause la responsabilité du gouvernement et de le renverser.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000019241038', '2026-01-01', 3);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'En France, la justice est-elle indépendante du pouvoir politique ?', 'vrai_faux', '["Oui, c''est un principe constitutionnel","Non"]'::jsonb, 'Oui, c''est un principe constitutionnel', 'L''indépendance de l''autorité judiciaire est garantie par l''article 64 de la Constitution. Le Président de la République en est le garant.', 'https://www.legifrance.gouv.fr/loda/article_lc/LEGIARTI000006527476', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Quel est le plus haut sommet de France ?', 'qcm', '["Le Mont Blanc (4 806 m)","Le Puy de Dôme","Le Mont Ventoux","Le Pic du Midi"]'::jsonb, 'Le Mont Blanc (4 806 m)', 'Le Mont Blanc, situé dans les Alpes à la frontière franco-italienne, culmine à 4 806 mètres. C''est le plus haut sommet d''Europe occidentale.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
INSERT INTO public.questions (module_id, enonce, type, options_json, bonne_reponse, explication, source_officielle, date_verification, difficulte) VALUES ('11111111-1111-1111-1111-111111111104', 'Combien d''habitants compte la France (environ) ?', 'qcm', '["68 millions","50 millions","80 millions","45 millions"]'::jsonb, '68 millions', 'La France compte environ 68 millions d''habitants (métropole + outre-mer) au 1er janvier 2026.', 'https://www.service-public.fr/particuliers/vosdroits/F2215', '2026-01-01', 1);
